import subprocess
from pathlib import Path

data = Path('/ctf-workspace/key_candidates/key0.der').read_bytes()

found = False
for idx in range(len(data)):
    if data[idx] != 0x30:
        continue
    if idx + 2 > len(data):
        continue
    length_byte = data[idx + 1]
    header_len = 2
    if length_byte & 0x80:
        length_len = length_byte & 0x7F
        if length_len == 0 or length_len > 4:
            continue
        if idx + 2 + length_len > len(data):
            continue
        length = int.from_bytes(data[idx + 2: idx + 2 + length_len], 'big')
        header_len += length_len
    else:
        length = length_byte
    end = idx + header_len + length
    if end > len(data):
        continue
    chunk = data[idx:end]
    try:
        proc = subprocess.run(["openssl", "asn1parse", "-inform", "DER"], input=chunk, capture_output=True, text=True)
    except FileNotFoundError:
        print('openssl missing')
        break
    if proc.returncode == 0:
        print('offset', idx, 'length', len(chunk))
        print(proc.stdout)
        found = True
        break
if not found:
    print('no valid ASN.1 parse found')
